#include <bits/stdc++.h>
using namespace std;
int a[5050][5001];
int main(){
    int n,s,x=1,m;
    cin>>n;
    a[1][0]=1;
    a[2][0]=2;
    for(int i=3;i<=n;i++){
        int j=0;
        while (x!=0){
            m=a[i][j]+a[i-1][j]+a[i-2][j];
            a[i][j]=m%10;
            a[i][j+1]=m/10;
            j++;
            x--;
        }
        x=j+1;
    }
    for (int j=5000;j>=0;j--){
        if (a[n][j]!=0){
            s=j;
            break;
        }
    }
    for (int i=s;i>=0;i--){
        cout<<a[n][i];
    }
    return 0;
}
